// Authorize + parse the callback_data. ADR-0005 + R-09: chat.id whitelist is the only authorization layer.
// callback_data format: 'dr:<verb>:<type>:<id>' — verbs a|d, types rs (railway-service, MVP).
const update = $input.first().json ?? {};
const cb = update.callback_query ?? update;
if (!cb || typeof cb.data !== 'string' || !cb.id) {
  throw new Error('No callback_query data on the inbound update — fail-closed');
}
const expected_chat = $env['TELEGRAM_CHAT_ID'] ?? '';
if (!expected_chat) throw new Error('TELEGRAM_CHAT_ID missing — fail-closed (R-09)');
const chat_id = cb.message?.chat?.id;
const message_id = cb.message?.message_id ?? cb.message?.id;
if (String(chat_id) !== String(expected_chat)) {
  return [{ json: { _action: 'unauthorized', _cb_id: cb.id, _chat_id: chat_id, _message_id: message_id } }];
}
const parts = cb.data.split(':');
if (parts.length !== 4 || parts[0] !== 'dr' || parts[2] !== 'rs') {
  return [{ json: { _action: 'unknown', _cb_id: cb.id, _chat_id: chat_id, _message_id: message_id, _raw: cb.data } }];
}
const verb = parts[1];
const id = parts[3];
if (verb === 'a') return [{ json: { _action: 'approve', _cb_id: cb.id, _chat_id: chat_id, _message_id: message_id, _resource_id: id } }];
if (verb === 'd') return [{ json: { _action: 'deny', _cb_id: cb.id, _chat_id: chat_id, _message_id: message_id, _resource_id: id } }];
return [{ json: { _action: 'unknown', _cb_id: cb.id, _chat_id: chat_id, _message_id: message_id, _raw: cb.data } }];

// Format the approve-arm status message. The Railway HTTP node output is in $input.first().json;
// the original parsed callback context (chat_id, message_id, cb_id, resource_id) lives on the
// Authorize & Parse node and must be re-fetched.
const r = $input.first().json;
const ctx = $('Authorize & Parse').first().json;
let text;
if (r?.errors && Array.isArray(r.errors) && r.errors.length > 0) {
  text = '❌ Railway serviceDelete failed for ' + ctx._resource_id + ': ' + r.errors.map((e) => e?.message ?? 'unknown').join('; ');
} else if (r?.data?.serviceDelete === true) {
  text = '✅ Railway service ' + ctx._resource_id + ' deleted.';
} else {
  text = '⚠ Railway serviceDelete returned unexpected response for ' + ctx._resource_id + ': ' + JSON.stringify(r).slice(0, 500);
}
return [{ json: { _chat_id: ctx._chat_id, _message_id: ctx._message_id, _cb_id: ctx._cb_id, _toast: 'Destroy executed', text } }];
